    listUsageEvents(tenantId?: string | null, poolId?: string | null, ratingStatus?: string | null, featureKey?: string | null, meterSlug?: string | null, subjectId?: string | null, fromTime?: string | null, toTime?: string | null, limit?: number, offset?: number, options?: RawAxiosRequestConfig): AxiosPromise<any>;

